mapper.select:
select  DISTINCT a.line_id,
a.line_name, a.line_type, a.work_center, a.status, a.remark, a.create_by, a.create_time, a.update_by, a.update_time,
a.site_id,b.site_name
FROM mes_line a
LEFT JOIN mes_site b ON a.site_id = b.site_id
LEFT JOIN mes_user_relate_line c on a.line_id = c.line_id
LEFT JOIN sys_user d ON c.user_id = d.user_id

 and a.line_name like concat('%', #{lineName}, '%')
 and a.line_type = #{lineType}
 and material_id = #{materialId}
 and material_id like concat('%', #{materialId}, '%')
 and d.material_name like concat('%', #{materialName}, '%')
 and a.work_center = #{workCenter}
 and b.site_name = #{siteName}
 and a.site_id = #{siteId}
 and a.status = #{status}

SELECT a.material_id,b.material_name,a.line_id
from mes_material_relate_line a,
mes_material_info b
WHERE  a.line_id = #{lineId}
AND a.material_id = b.id

SELECT a.user_id,b.user_name,a.line_id
from mes_user_relate_line a,
sys_user b
WHERE  a.line_id = #{lineId}
AND a.USER_id = b.user_id

select c.material_id,c.material_name
from (
SELECT a.material_id,b.material_name,a.line_id
from mes_material_relate_line a,
mes_material_info b
WHERE  a.line_id = #{lineId}
AND a.material_id = b.id
) c

mapper.insert:
insert into mes_line
line_name, line_type, work_center, status, remark, create_by, create_time, update_by, update_time, site_id
#{lineName}, #{lineType}, #{workCenter}, #{status}, #{remark}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{siteId}

mapper.update:
update mes_line
line_name = #{lineName}, line_type = #{lineType}, work_center = #{workCenter}, status = #{status}, remark = #{remark}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, site_id = #{siteId}
where line_id = #{lineId}
